local function validate_token(token)
    -- Validate token using a secure platform API (e.g., HMAC verification)
    local secret_key = "your_secret_key_here"
    local expected_signature = ngx.hmac_sha256(secret_key, token)
    return ngx.var.request_headers["X-Auth-Token"] == expected_signature
end

local function get_user_role(token)
    -- Get user role from the validated token (e.g., using a secure database query)
    if validate_token(token) then
        local decoded_token = ngx.decode_base64(token)
        local user_role = decoded_token:match("role=(%w+)")
        return user_role
    end
end

local function check_permissions(uri, method, user_role)
    -- Check if the endpoint is exempt from permission checks
    if uri:find("/admin") or uri:find("/api") then
        return true
    end

    -- Define allowed actions for each role (e.g., using a secure database query)
    local allowed_actions = {
        ["admin"] = {"GET", "POST", "PUT", "DELETE"},
        ["user"]  = {"GET", "POST"}
    }

    -- Check if the user has permission to access the endpoint
    return method and allowed_actions[user_role] and table.contains(allowed_actions[user_role], method)
end

local function auth_check()
    local token = ngx.var.request_headers["X-Auth-Token"]
    if not token then
        ngx.status = 401
        ngx.say("Unauthorized")
        return false
